// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title Escrow
 * @notice A trustless escrow contract for peer-to-peer transactions.
 *         Buyer deposits ETH → Seller delivers → Buyer confirms → Funds released.
 *         If disputed, arbiter resolves.
 * @dev Demonstrates state machines, role-based access, and pull payments.
 */
contract Escrow {

    // ─── Custom Errors (gas-efficient vs require strings) ─────────────────────
    error Escrow__NotBuyer();
    error Escrow__NotSeller();
    error Escrow__NotArbiter();
    error Escrow__WrongState(State expected, State current);
    error Escrow__InsufficientDeposit(uint256 required, uint256 sent);
    error Escrow__TransferFailed();
    error Escrow__DeadlinePassed();
    error Escrow__DeadlineNotReached();

    // ─── State Machine ─────────────────────────────────────────────────────────
    enum State {
        AWAITING_PAYMENT,   // 0 - Created, buyer hasn't funded yet
        AWAITING_DELIVERY,  // 1 - Funded, waiting for seller to deliver
        COMPLETE,           // 2 - Buyer confirmed, funds sent to seller
        REFUNDED,           // 3 - Buyer got refund
        DISPUTED            // 4 - Under arbiter review
    }

    // ─── Roles ─────────────────────────────────────────────────────────────────
    address public immutable buyer;
    address public immutable seller;
    address public immutable arbiter;

    // ─── Escrow Details ────────────────────────────────────────────────────────
    uint256 public immutable price;
    uint256 public immutable deadline;       // Unix timestamp: buyer can reclaim if expired
    uint256 public immutable arbiterFeePercent; // % of price arbiter earns if called in

    State public currentState;

    // ─── Events ────────────────────────────────────────────────────────────────
    event Funded(address indexed buyer, uint256 amount, uint256 deadline);
    event DeliveryConfirmed(address indexed buyer, uint256 amountReleased);
    event RefundIssued(address indexed buyer, uint256 amount);
    event DisputeRaised(address indexed raisedBy);
    event DisputeResolved(address indexed winner, uint256 amount);

    // ─── Modifiers ─────────────────────────────────────────────────────────────
    modifier onlyBuyer() {
        if (msg.sender != buyer) revert Escrow__NotBuyer();
        _;
    }

    modifier onlySeller() {
        if (msg.sender != seller) revert Escrow__NotSeller();
        _;
    }

    modifier onlyArbiter() {
        if (msg.sender != arbiter) revert Escrow__NotArbiter();
        _;
    }

    modifier inState(State _expected) {
        if (currentState != _expected)
            revert Escrow__WrongState(_expected, currentState);
        _;
    }

    // ─── Constructor ───────────────────────────────────────────────────────────

    /**
     * @param _seller          Address that will receive payment on delivery
     * @param _arbiter         Neutral third party who resolves disputes
     * @param _price           Exact ETH amount (in wei) buyer must deposit
     * @param _durationDays    How many days buyer has to confirm delivery
     * @param _arbiterFeePercent Percentage (0–10) arbiter earns if dispute occurs
     */
    constructor(
        address _seller,
        address _arbiter,
        uint256 _price,
        uint256 _durationDays,
        uint256 _arbiterFeePercent
    ) {
        require(_seller != address(0), "Invalid seller");
        require(_arbiter != address(0), "Invalid arbiter");
        require(_seller != msg.sender, "Buyer cannot be seller");
        require(_arbiter != msg.sender && _arbiter != _seller, "Arbiter conflict");
        require(_price > 0, "Price must be > 0");
        require(_arbiterFeePercent <= 10, "Max arbiter fee is 10%");

        buyer = msg.sender;          // whoever deploys IS the buyer
        seller = _seller;
        arbiter = _arbiter;
        price = _price;
        deadline = block.timestamp + (_durationDays * 1 days);
        arbiterFeePercent = _arbiterFeePercent;
        currentState = State.AWAITING_PAYMENT;
    }

    // ─── Core Functions ────────────────────────────────────────────────────────

    /**
     * @notice Buyer funds the escrow. Must send exactly `price` wei.
     */
    function fund()
        external
        payable
        onlyBuyer
        inState(State.AWAITING_PAYMENT)
    {
        if (msg.value != price)
            revert Escrow__InsufficientDeposit(price, msg.value);

        currentState = State.AWAITING_DELIVERY;
        emit Funded(buyer, msg.value, deadline);
    }

    /**
     * @notice Buyer confirms they received the goods/service. Releases funds to seller.
     */
    function confirmDelivery()
        external
        onlyBuyer
        inState(State.AWAITING_DELIVERY)
    {
        currentState = State.COMPLETE;

        uint256 amount = address(this).balance;
        emit DeliveryConfirmed(buyer, amount);

        (bool success, ) = seller.call{value: amount}("");
        if (!success) revert Escrow__TransferFailed();
    }

    /**
     * @notice Buyer can reclaim funds ONLY after the deadline passes.
     *         Prevents abuse: buyer can't instantly refund themselves.
     */
    function claimRefund()
        external
        onlyBuyer
        inState(State.AWAITING_DELIVERY)
    {
        if (block.timestamp < deadline)
            revert Escrow__DeadlineNotReached();

        currentState = State.REFUNDED;

        uint256 amount = address(this).balance;
        emit RefundIssued(buyer, amount);

        (bool success, ) = buyer.call{value: amount}("");
        if (!success) revert Escrow__TransferFailed();
    }

    /**
     * @notice Either buyer or seller can raise a dispute.
     *         Hands control to the arbiter.
     */
    function raiseDispute()
        external
        inState(State.AWAITING_DELIVERY)
    {
        if (msg.sender != buyer && msg.sender != seller)
            revert Escrow__NotBuyer(); // reusing for brevity — both parties allowed

        currentState = State.DISPUTED;
        emit DisputeRaised(msg.sender);
    }

    /**
     * @notice Arbiter resolves dispute. Decides who gets the funds.
     * @param favorSeller  true = seller wins, false = buyer gets refund
     *
     * Arbiter always earns their fee (taken from total balance).
     */
    function resolveDispute(bool favorSeller)
        external
        onlyArbiter
        inState(State.DISPUTED)
    {
        uint256 totalBalance = address(this).balance;
        uint256 arbiterFee = (totalBalance * arbiterFeePercent) / 100;
        uint256 remainder = totalBalance - arbiterFee;

        currentState = favorSeller ? State.COMPLETE : State.REFUNDED;

        address winner = favorSeller ? seller : buyer;
        emit DisputeResolved(winner, remainder);

        // Pay arbiter first
        if (arbiterFee > 0) {
            (bool feeSuccess, ) = arbiter.call{value: arbiterFee}("");
            if (!feeSuccess) revert Escrow__TransferFailed();
        }

        // Pay winner
        (bool success, ) = winner.call{value: remainder}("");
        if (!success) revert Escrow__TransferFailed();
    }

    // ─── View Functions ────────────────────────────────────────────────────────

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function getState() external view returns (State) {
        return currentState;
    }

    function getDeadlineRemaining() external view returns (int256) {
        return int256(deadline) - int256(block.timestamp);
    }

    function getEscrowDetails() external view returns (
        address _buyer,
        address _seller,
        address _arbiter,
        uint256 _price,
        uint256 _deadline,
        State _state,
        uint256 _balance
    ) {
        return (buyer, seller, arbiter, price, deadline, currentState, address(this).balance);
    }
}

